    32→int ucstrncmp(
    33→	const ldap_unicode_t *u1,
    34→	const ldap_unicode_t *u2,
    35→	ber_len_t n )
    36→{
    37→	for(; 0 < n; ++u1, ++u2, --n ) {
    38→		if( *u1 != *u2 ) {
    39→			return *u1 < *u2 ? -1 : +1;
    40→		}
